"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["41094"],{22245(t){t.exports=JSON.parse('{"tag":{"label":"senior","permalink":"/sysanalyst-kb.github.io/docs/tags/senior","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":8,"items":[{"id":"integration/api-gateway","title":"API Gateway pattern","description":"API Gateway \u2014 \u044D\u0442\u043E \u0435\u0434\u0438\u043D\u0430\u044F \u0442\u043E\u0447\u043A\u0430 \u0432\u0445\u043E\u0434\u0430 \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u0432 (web, mobile, third-party), \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0437\u0430\u043F\u0440\u043E\u0441\u044B \u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043C, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u043A\u0440\u043E\u0441\u0441-\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0438 \u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-gateway"},{"id":"architecture/ddd-intro","title":"DDD \u2014 Domain-Driven Design (\u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435)","description":"Domain-Driven Design (DDD) \u2014 \u044D\u0442\u043E \u043F\u043E\u0434\u0445\u043E\u0434 \u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044E \u041F\u041E, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0431\u0438\u0437\u043D\u0435\u0441-\u043B\u043E\u0433\u0438\u043A\u0438 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0446\u0435\u043D\u0442\u0440\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F. DDD \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u043D\u0430\u0431\u043E\u0440 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0439 \u0438 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u043E\u0432 \u0434\u043B\u044F \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043D\u043E\u0439 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 (domain) \u0432 \u043A\u043E\u0434\u0435.","permalink":"/sysanalyst-kb.github.io/docs/architecture/ddd-intro"},{"id":"integration/enterprise-integration-patterns","title":"Enterprise Integration Patterns (EIP)","description":"Enterprise Integration Patterns (EIP) \u2014 \u044D\u0442\u043E \u043A\u0430\u0442\u0430\u043B\u043E\u0433 \u0442\u0438\u043F\u043E\u0432\u044B\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0434\u043B\u044F \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441\u0438\u0441\u0442\u0435\u043C, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0432 \u043A\u043D\u0438\u0433\u0435 Gregor Hohpe \u0438 Bobby Woolf (2004). EIP \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0430\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u043C \u0438 \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u2014 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u0448\u0438\u043D (Kafka, RabbitMQ, Azure Service Bus) \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u044E\u0442 \u044D\u0442\u0438 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B.","permalink":"/sysanalyst-kb.github.io/docs/integration/enterprise-integration-patterns"},{"id":"integration/event-storming-advanced","title":"Event Storming \u2014 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0439 \u0443\u0440\u043E\u0432\u0435\u043D\u044C","description":"Event Storming \u2014 \u044D\u0442\u043E \u043C\u0435\u0442\u043E\u0434\u0438\u043A\u0430 \u0432\u043E\u0440\u043A\u0448\u043E\u043F\u0430 \u0434\u043B\u044F \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0431\u0438\u0437\u043D\u0435\u0441-\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432 \u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u0438\u0441\u0442\u0435\u043C. \u041D\u0430 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u043E\u043C \u0443\u0440\u043E\u0432\u043D\u0435 Event Storming \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E DDD: discovery bounded contexts, \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432, \u0440\u0435\u0432\u0435\u0440\u0441-\u0438\u043D\u0436\u0438\u043D\u0438\u0440\u0438\u043D\u0433 legacy.","permalink":"/sysanalyst-kb.github.io/docs/integration/event-storming-advanced"},{"id":"architecture/hexagonal-architecture","title":"Hexagonal Architecture (Ports & Adapters)","description":"Hexagonal Architecture (\u0442\u0430\u043A\u0436\u0435 Ports & Adapters) \u2014 \u044D\u0442\u043E \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0439 \u043F\u0430\u0442\u0442\u0435\u0440\u043D, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0438\u0437\u043E\u043B\u0438\u0440\u0443\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441-\u043B\u043E\u0433\u0438\u043A\u0443 \u043E\u0442 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0441\u0438\u0441\u0442\u0435\u043C (\u0411\u0414, API, UI, message broker).","permalink":"/sysanalyst-kb.github.io/docs/architecture/hexagonal-architecture"},{"id":"architecture/saga-pattern","title":"Saga pattern \u2014 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F\u043C\u0438","description":"Saga \u2014 \u044D\u0442\u043E \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u0434\u043B\u044F \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u044B\u043C\u0438 \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F\u043C\u0438 \u0432 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0435. \u041A\u043E\u0433\u0434\u0430 \u043E\u0434\u043D\u0430 \u0431\u0438\u0437\u043D\u0435\u0441-\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u044F \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u0435\u0442 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432, \u043E\u0431\u044B\u0447\u043D\u0430\u044F ACID-\u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F (\u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0411\u0414) \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u0430. Saga \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0438\u0440\u0443\u0435\u0442 \u0448\u0430\u0433\u0438 \u0438 \u043A\u043E\u043C\u043F\u0435\u043D\u0441\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/saga-pattern"},{"id":"requirements/srs","title":"SRS \u2014 Software Requirements Specification","description":"SRS (Software Requirements Specification) \u2014 \u044D\u0442\u043E \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0447\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u0430 \u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0438\u0441\u0442\u0435\u043C\u0430, \u0435\u0451 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u0438 \u0430\u0442\u0440\u0438\u0431\u0443\u0442\u044B \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430. SRS \u2014 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0430\u0440\u0442\u0435\u0444\u0430\u043A\u0442 \u044D\u0442\u0430\u043F\u0430 \u0430\u043D\u0430\u043B\u0438\u0437\u0430 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0439.","permalink":"/sysanalyst-kb.github.io/docs/requirements/srs"},{"id":"architecture/strangler-fig","title":"Strangler Fig \u2014 \u043C\u0438\u0433\u0440\u0430\u0446\u0438\u044F legacy","description":"Strangler Fig (\u0438\u043B\u0438 Strangler Pattern) \u2014 \u044D\u0442\u043E \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044F \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u0439 \u0437\u0430\u043C\u0435\u043D\u044B legacy-\u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043D\u0430 \u043D\u043E\u0432\u0443\u044E \u0431\u0435\u0437 \u043F\u0440\u043E\u0441\u0442\u043E\u0435\u0432 \u0438 big-bang \u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/strangler-fig"}],"unlisted":false}}')}}]);